<?php require_once __DIR__.'/../app/poster.php'; $msg=''; if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf(); try{ if(isset($_POST['interval'])){set_setting('cron_interval_minutes',(string)(int)$_POST['interval']); set_setting('auto_update_enabled',isset($_POST['auto_update_enabled'])?'1':'0'); $msg='設定を保存しました。';} if(isset($_POST['rss'])) {$r=fetch_all_feeds();$msg='RSS取得完了 OK '.$r['ok'].' / NG '.$r['ng']; set_setting('last_rss_cron',date('Y-m-d H:i:s'));} if(isset($_POST['post'])) {$id=run_post();$msg='投稿処理完了 ID '.$id; set_setting('last_post_cron',date('Y-m-d H:i:s'));} }catch(Throwable $e){$msg='エラー: '.$e->getMessage(); log_event('error','手動Cron失敗',$e->getMessage());}} admin_header('Cron設定'); if($msg)echo'<p class=notice>'.e($msg).'</p>'; $php=PHP_BINARY?:'php'; $interval=(int)setting('cron_interval_minutes',60); $lastPost=setting('last_post_cron',''); $remaining=auto_update_remaining_seconds($lastPost,$interval); $nextPost=$lastPost?date('Y-m-d H:i:s',strtotime($lastPost)+max(1,$interval)*60):'未実行'; echo'<form method=post><input type=hidden name=csrf value='.csrf_token().'><label>実行間隔(分)<input name=interval value="'.e($interval).'"></label><label><input type=checkbox name=auto_update_enabled value=1 '.(auto_update_enabled()?'checked':'').'>自動更新を有効化</label><button>保存</button><button name=rss value=1>RSS取得実行</button><button name=post value=1>livedoor投稿実行</button></form><div class=card><h3>シンサーバー向けCron例</h3><p>RSS取得: <code>'.$php.' '.APP_ROOT.'/cron/fetch.php</code></p><p>投稿: <code>'.$php.' '.APP_ROOT.'/cron/post.php</code></p><p>URL実行: <code>'.e(app_absolute_url('/cron/fetch.php')).'</code></p><p>自動更新: '.(auto_update_enabled()?'有効':'無効').'</p><p>次回投稿目安: '.e($nextPost).'</p><p>投稿までの残り時間: <span id=autoUpdateTimer data-seconds="'.e($remaining).'">'.e(format_seconds($remaining)).'</span></p><p>最終RSS実行: '.e(setting('last_rss_cron','-')).'</p><p>最終投稿実行: '.e($lastPost?:'-').'</p></div><script>const t=document.getElementById("autoUpdateTimer");if(t){let s=parseInt(t.dataset.seconds,10)||0;setInterval(()=>{if(s>0)s--;const h=String(Math.floor(s/3600)).padStart(2,"0"),m=String(Math.floor(s%3600/60)).padStart(2,"0"),sec=String(s%60).padStart(2,"0");t.textContent=h+":"+m+":"+sec;},1000);}</script>'; admin_footer();
